import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';

const Logo = () => (
  <div style={{display:'flex',alignItems:'center',gap:12,justifyContent:'center',marginBottom:28}}>
    <div style={{width:44,height:44,background:'var(--g-brand)',borderRadius:13,display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 6px 20px rgba(99,102,241,.5)'}}>
      <span style={{color:'#fff',fontFamily:'var(--ff-h)',fontWeight:800,fontSize:22}}>D</span>
    </div>
    <span style={{fontFamily:'var(--ff-h)',fontWeight:800,fontSize:24,letterSpacing:'-0.03em'}}>DeLaxiY</span>
  </div>
);

export default function AuthModal({ mode, onClose, onSwitch }) {
  const { login, register, loading } = useAuth();
  const { add } = useToast();
  const navigate = useNavigate();

  const [name,     setName]     = useState('');
  const [email,    setEmail]    = useState('');
  const [password, setPassword] = useState('');
  const [confirm,  setConfirm]  = useState('');
  const [errs,     setErrs]     = useState({});
  const [show,     setShow]     = useState(false);

  const clearE = k => setErrs(p => ({...p, [k]:null, _:null}));

  function validate() {
    const e = {};
    if (mode==='register' && !name.trim())      e.name     = 'Please fill the field';
    if (!email.trim())                           e.email    = 'Please fill the field';
    else if (!/^[^@]+@[^@]+\.[^@]+$/.test(email)) e.email  = 'Invalid email address';
    if (!password)                               e.password = 'Please fill the field';
    else if (password.length < 6)               e.password = 'Minimum 6 characters';
    if (mode==='register' && password!==confirm) e.confirm  = 'Passwords do not match';
    return e;
  }

  async function submit(e) {
    e.preventDefault();
    const ev = validate();
    if (Object.keys(ev).length) { setErrs(ev); return; }
    try {
      if (mode==='login') await login(email, password);
      else                await register(name, email, password);
      add(mode==='login' ? '🎉 Welcome back!' : '🚀 Account created!', 'success');
      onClose();
      navigate('/dashboard');
    } catch(err) { setErrs({_:err.message}); }
  }

  const inputSt = (hasErr) => ({
    background: 'rgba(255,255,255,0.05)',
    border: `1.5px solid ${hasErr ? 'var(--rose)' : 'var(--border2)'}`,
    borderRadius: 'var(--r2)', padding:'12px 16px',
    color:'var(--t1)', fontFamily:'var(--ff-b)', fontSize:'14px',
    width:'100%', outline:'none', transition:'all .2s',
    boxSizing:'border-box',
  });

  return (
    <div className="overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal modal-sm scale-in" onClick={e=>e.stopPropagation()}>

        {/* Gradient header accent */}
        <div style={{height:4,background:'var(--g-brand)',borderRadius:'var(--r4) var(--r4) 0 0'}}/>

        <div style={{padding:'36px 36px 28px'}}>
          <Logo />

          <div style={{textAlign:'center',marginBottom:28}}>
            <h2 style={{fontSize:22,marginBottom:6}}>{mode==='login'?'Welcome back':'Create account'}</h2>
            <p style={{fontSize:13,color:'var(--t2)'}}>
              {mode==='login' ? 'Sign in to your DeLaxiY account' : 'Start managing orders and dashboards'}
            </p>
          </div>

          {errs._ && (
            <div className="fade-in" style={{background:'rgba(244,63,94,.12)',border:'1px solid rgba(244,63,94,.3)',borderRadius:'var(--r2)',padding:'11px 16px',color:'var(--rose)',fontSize:13,marginBottom:18,display:'flex',alignItems:'center',gap:8}}>
              <span>✕</span>{errs._}
            </div>
          )}

          <form onSubmit={submit} style={{display:'flex',flexDirection:'column',gap:16}} autoComplete="on">
            {mode==='register' && (
              <div className="form-group">
                <label className="form-label" htmlFor="am-name">Full Name</label>
                <input id="am-name" name="fullname" type="text" placeholder="Priyanka T K"
                  value={name} onChange={e=>{setName(e.target.value);clearE('name');}}
                  style={inputSt(errs.name)} autoComplete="name" autoFocus />
                {errs.name && <span className="form-error">⚠ {errs.name}</span>}
              </div>
            )}

            <div className="form-group">
              <label className="form-label" htmlFor="am-email">Email Address</label>
              <input id="am-email" name="email" type="email" placeholder="you@example.com"
                value={email} onChange={e=>{setEmail(e.target.value);clearE('email');}}
                style={inputSt(errs.email)} autoComplete="email" />
              {errs.email && <span className="form-error">⚠ {errs.email}</span>}
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="am-pwd">Password</label>
              <div style={{position:'relative'}}>
                <input id="am-pwd" name="password" type={show?'text':'password'} placeholder="Minimum 6 characters"
                  value={password} onChange={e=>{setPassword(e.target.value);clearE('password');}}
                  style={{...inputSt(errs.password),paddingRight:46}} autoComplete={mode==='login'?'current-password':'new-password'} />
                <button type="button" onClick={()=>setShow(!show)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'var(--t2)',cursor:'pointer',fontSize:16,padding:2}}>
                  {show?'🙈':'👁'}
                </button>
              </div>
              {errs.password && <span className="form-error">⚠ {errs.password}</span>}
            </div>

            {mode==='register' && (
              <div className="form-group">
                <label className="form-label" htmlFor="am-conf">Confirm Password</label>
                <input id="am-conf" name="confirmPassword" type="password" placeholder="Repeat your password"
                  value={confirm} onChange={e=>{setConfirm(e.target.value);clearE('confirm');}}
                  style={inputSt(errs.confirm)} autoComplete="new-password" />
                {errs.confirm && <span className="form-error">⚠ {errs.confirm}</span>}
              </div>
            )}

            <button className="btn btn-primary" type="submit" disabled={loading}
              style={{width:'100%',justifyContent:'center',padding:14,fontSize:15,marginTop:4,borderRadius:'var(--r2)'}}>
              {loading
                ? <><span className="spinner"/>{mode==='login'?' Signing in…':' Creating account…'}</>
                : mode==='login' ? '→ Sign In' : '→ Create Account'
              }
            </button>
          </form>

          <div style={{textAlign:'center',marginTop:20,fontSize:13,color:'var(--t2)'}}>
            {mode==='login'
              ? <>Don't have an account?{' '}<button type="button" onClick={()=>onSwitch('register')} style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>Register free</button></>
              : <>Already have an account?{' '}<button type="button" onClick={()=>onSwitch('login')} style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>Sign in</button></>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
